import java.util.*;

public class ArrayListOperation {
    public static void main(String[] args) {
        // (1) 创建ArrayList并添加10个随机整数
        List<Integer> list = new ArrayList<>();
        Random rand = new Random();
        for (int i = 0; i < 10; i++) {
            list.add(rand.nextInt(100) + 1);
        }

        // (2) 输出原始列表
        System.out.println("原始列表：" + list);

        // (3) 删除所有偶数 - 使用迭代器避免并发修改异常
        Iterator<Integer> iterator = list.iterator();
        while (iterator.hasNext()) {
            int num = iterator.next();
            if (num % 2 == 0) {
                iterator.remove();
            }
        }
        System.out.println("删除偶数后：" + list);

        // (4) 排序并输出
        Collections.sort(list);
        System.out.println("排序后：" + list);
    }
}

import java.util.ArrayList;

// 抽象类
abstract class LibraryItem {
    protected String id;
    protected String title;
    protected boolean isAvailable;

    public LibraryItem(String id, String title, boolean isAvailable) {
        this.id = id;
        this.title = title;
        this.isAvailable = isAvailable;
    }

    public boolean isAvailable() {
        return isAvailable;
    }

    public abstract String getItemType();

    public void borrow() {
        if (isAvailable) {
            isAvailable = false;
            System.out.println(title + "已借出");
        } else {
            System.out.println(title + "已被借出");
        }
    }

    public void returnItem() {
        isAvailable = true;
        System.out.println(title + "已归还");
    }

    public void displayInfo() {
        System.out.println("编号：" + id + "，标题：" + title +
                "，类型：" + getItemType() +
                "，状态：" + (isAvailable ? "可借" : "已借出"));
    }
}

// 接口
interface Renewable {
    boolean canRenew();
    void renew();
}

// Book类实现
class Book extends LibraryItem implements Renewable {
    private String author;
    private String isbn;
    private int renewCount = 0;

    public Book(String id, String title, boolean isAvailable, String author, String isbn) {
        super(id, title, isAvailable);
        this.author = author;
        this.isbn = isbn;
    }

    @Override
    public String getItemType() {
        return "图书";
    }

    @Override
    public boolean canRenew() {
        return renewCount < 2; // 最多续借2次
    }

    @Override
    public void renew() {
        if (canRenew()) {
            renewCount++;
            System.out.println(title + "续借成功，当前续借次数：" + renewCount);
        } else {
            System.out.println(title + "已达到最大续借次数");
        }
    }
}

// Magazine 类
class Magazine extends LibraryItem {
    private int issueNumber;
    private String publisher;

    public Magazine(String id, String title, boolean isAvailable, int issueNumber, String publisher) {
        super(id, title, isAvailable);
        this.issueNumber = issueNumber;
        this.publisher = publisher;
    }

    @Override
    public String getItemType() {
        return "杂志";
    }

    @Override
    public void displayInfo() {
        super.displayInfo();
        System.out.println("   期号：" + issueNumber + " | 出版社：" + publisher);
    }
}

