class LibraryTest {
    public static void main(String[] args) {
        ArrayList<LibraryItem> libraryItems = new ArrayList<>();

        Book book1 = new Book("B001", "Java编程思想", true, "Bruce Eckel","978-7-111-21382-6");
        Magazine magazine1 = new Magazine("M001", "计算机世界", true, 202405, "中国计算机报社");

        libraryItems.add(book1);
        libraryItems.add(magazine1);

        // 多态遍历
        for (LibraryItem item : libraryItems) {
            item.displayInfo();
            // 尝试借出
            if (item.isAvailable()) {
                item.borrow();
            }
            // 尝试续借（仅针对实现了Renewable接口的物品）
            if (item instanceof Renewable) {
                ((Renewable) item).renew();
            }
            System.out.println("-------------------");
        }
    }
}

abstract class Vehicle {
    public static final double DAILY_RATE = 200;
    protected String plateNumber;

    public Vehicle(String plateNumber) {
        this.plateNumber = plateNumber;
    }
    public abstract void displayBasicInfo();
}

interface Rentable {
    double calculateRentFee(int days);
    boolean isAvailable();
}

class Car extends Vehicle implements Rentable {
    private String brand;
    private int seats;

    public Car(String plateNumber, String brand, int seats) {
        super(plateNumber);
        this.brand = brand;
        this.seats = seats;
    }

    @Override
    public void displayBasicInfo() {
        System.out.println("轿车：" + plateNumber + " 品牌：" + brand);
    }

    @Override
    public double calculateRentFee(int days) {
        return DAILY_RATE * days;
    }

    @Override
    public boolean isAvailable() {
        return true;
    }
}

class LuxuryCar extends Car {
    private boolean chauffeurService;
    private double extraFee;

    public LuxuryCar(String plateNumber, String brand, int seats, boolean chauffeurService, double extraFee) {
        super(plateNumber, brand, seats);
        this.chauffeurService = chauffeurService;
        this.extraFee = extraFee;
    }

    @Override
    public void displayBasicInfo() {
        super.displayBasicInfo();
        System.out.println("附加服务：" + (chauffeurService ? "包含司机" : "无司机"));
    }

    @Override
    public double calculateRentFee(int days) {
        return DAILY_RATE * days * 1.5 + extraFee;
    }
}

