import java.io.*;
import java.util.*;

class Student {
    String id, name;
    double score;
    public Student(String id, String name, double score) {
        this.id = id; this.name = name; this.score = score;
    }
    public String toString() { return id + "," + name + "," + score; }
}

public class StudentManager {
    public static void main(String[] args) throws IOException {
        List<Student> students = new ArrayList<>();
        students.add(new Student("1001", "张三", 85.5));
        students.add(new Student("1002", "李四", 92.0));
        students.add(new Student("1003", "王五", 78.5));

        // 写入文件
        try (BufferedWriter writer = new BufferedWriter(new FileWriter("students.txt"))) {
            for (Student s : students) {
                writer.write(s.toString());
                writer.newLine();
            }
        }

        // 读取文件并计算平均分
        double total = 0;
        int count = 0;
        try (BufferedReader reader = new BufferedReader(new FileReader("students.txt"))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split(",");
                System.out.println("读取学生：" + parts[1] + " 成绩：" + parts[2]);
                total += Double.parseDouble(parts[2]);
                count++;
            }
        }
        if (count > 0) System.out.println("平均成绩：" + (total / count));
    }
}

abstract class Employee {
